// Monta a mensagem de chamada da matinal — data e contagem regressiva dinâmicas (America/Bahia).
const TZ = 'America/Bahia';
const agora = new Date();
// data formatada pt-BR
const diaSemana = agora.toLocaleDateString('pt-BR', { weekday: 'long', timeZone: TZ });
const dataFmt = agora.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', year: 'numeric', timeZone: TZ });
// contagens regressivas (em dias) a partir de hoje
const hojeBA = new Date(agora.toLocaleString('en-US', { timeZone: TZ }));
hojeBA.setHours(0,0,0,0);
const diasAte = (alvoISO) => Math.max(0, Math.round((new Date(alvoISO) - hojeBA) / 86400000));
const diasFimMes = diasAte('2026-06-30T00:00:00');
const diasInaug = diasAte('2026-07-01T00:00:00');
// link do Meet: fixo via env (recorrente) — troque MEET_URL_MATINAL quando criar o Meet recorrente
const meet = $env.MEET_URL_MATINAL || 'https://playbook.ssfcard.ia.br';
const hora = $env.MATINAL_HORA || '08h';

const msg =
`\u2600\uFE0F Bom dia, equipe SST Card! (${diaSemana}, ${dataFmt})\n\n` +
`\uD83C\uDFED MATINAL \u00e0s ${hora}\n\uD83D\uDC49 Meet: ${meet}\n\n` +
`Foco: a M\u00c1QUINA de cobran\u00e7a rodando. Meta R$ 20.000 at\u00e9 30/06 \u2014 faltam ${diasFimMes} dias. O dinheiro est\u00e1 na base, \u00e9 s\u00f3 executar.\n\n` +
`Cheguem com a cantada de ONTEM na m\u00e3o:\n` +
`\u2022 Karine \u2014 total arrecadado + mix (Pix/cart\u00e3o/dinheiro) + lista dos \"n\u00e3o evoluiu\" pro Lucas\n` +
`\u2022 Lucas \u2014 cancelamentos do dia (pagou pra encerrar?) + n\u00fameros atualizados\n` +
`\u2022 Raquel \u2014 contatos enriquecidos + leads novos\n\n` +
`\u23F1\uFE0F 15 minutos, direto ao ponto. \uD83D\uDE80  (${diasInaug} dias pra inaugura\u00e7\u00e3o do Bairro da Paz)`;

return [{ json: { mensagem: msg } }];
